// SocialLoginManager.kt
package com.example.sociallogin

import android.app.Activity
import android.content.Intent
import androidx.activity.result.ActivityResultLauncher
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class SocialLoginManager(private val activity: Activity) {

    interface SocialLoginCallback {
        fun onSuccess(provider: String, userId: String, token: String)
        fun onError(provider: String, error: String)
        fun onCancel(provider: String)
    }

    private var callback: SocialLoginCallback? = null
    private lateinit var googleSignInClient: GoogleSignInClient
    private lateinit var facebookCallbackManager: CallbackManager

    fun initialize() {
        // Google Sign-In - uses web client ID from strings.xml
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(activity.getString(R.string.google_web_client_id))
            .requestEmail()
            .build()

        googleSignInClient = GoogleSignIn.getClient(activity, gso)

        // Facebook Login - uses app ID from strings.xml
        facebookCallbackManager = CallbackManager.Factory.create()
    }

    fun loginWithGoogle(launcher: ActivityResultLauncher<Intent>) {
        val signInIntent = googleSignInClient.signInIntent
        launcher.launch(signInIntent)
    }

    fun handleGoogleSignInResult(data: Intent?) {
        val task = GoogleSignIn.getSignedInAccountFromIntent(data)
        handleGoogleSignInTask(task)
    }

    private fun handleGoogleSignInTask(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            callback?.onSuccess(
                "Google",
                account.id ?: "",
                account.idToken ?: ""
            )
        } catch (e: ApiException) {
            callback?.onError("Google", e.message ?: "Unknown error")
        }
    }

    fun loginWithFacebook() {
        LoginManager.getInstance().registerCallback(facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    callback?.onSuccess(
                        "Facebook",
                        result.accessToken.userId,
                        result.accessToken.token
                    )
                }

                override fun onCancel() {
                    callback?.onCancel("Facebook")
                }

                override fun onError(error: FacebookException) {
                    callback?.onError("Facebook", error.message ?: "Unknown error")
                }
            })

        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            listOf("email", "public_profile")
        )
    }

    fun handleFacebookResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun setCallback(callback: SocialLoginCallback) {
        this.callback = callback
    }

    fun signOut() {
        googleSignInClient.signOut()
        LoginManager.getInstance().logOut()
    }
}